import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    grid = data[1:]

    o_positions = []
    for i in range(N):
        for j in range(N):
            if grid[i][j] == 'o':
                o_positions.append((i, j))

    count = 0
    for i in range(len(o_positions)):
        for j in range(i + 1, len(o_positions)):
            for k in range(j + 1, len(o_positions)):
                a, b, c = o_positions[i], o_positions[j], o_positions[k]
                rows = set([a[0], b[0], c[0]])
                cols = set([a[1], b[1], c[1]])
                if len(rows) == 2 and len(cols) == 2:
                    count += 1
    print(count)

if __name__ == "__main__":
    main()
